+typedef std::shared_ptr<Person> PersonPtr;
+typedef std::shared_ptr<const Person> PersonConstPtr;
+typedef std::weak_ptr<Person> PersonWeakPtr;
+typedef std::weak_ptr<const Person> PersonWeakConstPtr;
+
