-      for (auto const& kv : faces)
-      {
-        current_ids.insert(kv.first);
-      }
-      break;
-    case FeatureType::body:
-      for (auto const& kv : bodies)
-      {
-        current_ids.insert(kv.first);
-      }
-      break;
