-    {
-      to_remove.insert(id);
-    }
-  }
-
-  switch (feature)
-  {
-    case FeatureType::face:
-      for (auto id : to_remove)
-      {
-        faces.erase(id);
-
-        // invoke all the callbacks
-        for (auto& cb : face_lost_callbacks)
