+boost::optional<geometry_msgs::msg::TransformStamped> Body::transform() const
+{
+  try {
+    auto transform = tf_buffer_.lookupTransform(
+      _reference_frame, frame(),
+      tf2::TimePointZero);
+
+    return transform;
+  } catch (const tf2::TransformException & ex) {
+    RCLCPP_WARN_STREAM(
